/**
 * NotificationCenter
 *
 * Self-contained bell dropdown that:
 *  - Displays unread badge count on the bell icon
 *  - Fetches notification list on open
 *  - Lets the user filter All / Chưa đọc
 *  - Marks notifications read on click and navigates to actionUrl
 *  - "Mark all as read" button
 *  - Load-more pagination
 *  - Delete single notification
 *  - Closes on outside click or Escape key
 */
import React, {
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import { useNavigate } from 'react-router-dom';
import { useAppDispatch, useAppSelector } from '../../../store/hooks';
import {
  fetchNotifications,
  fetchMoreNotifications,
  markNotificationRead,
  markAllNotificationsRead,
  markEntityNotificationsRead,
  deleteNotification,
} from '../../../store/slices/notificationSlice';
import { useSignalREvent } from '../../../services/signalr/hook';
import { HubEvent } from '../../../services/signalr/types';
import type { NotificationDto } from '../../../services/notifications/types';
import { NotificationType } from '../../../services/notifications/types';
import styles from './NotificationCenter.module.css';

// ── Helpers ───────────────────────────────────────────────────────────────────

function relativeTime(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const mins  = Math.floor(diff / 60_000);
  const hours = Math.floor(diff / 3_600_000);
  const days  = Math.floor(diff / 86_400_000);
  if (mins < 1)   return 'Vừa xong';
  if (mins < 60)  return `${mins} phút trước`;
  if (hours < 24) return `${hours} giờ trước`;
  if (days < 7)   return `${days} ngày trước`;
  return new Date(iso).toLocaleDateString('vi-VN');
}

function getIconClass(type: string): { icon: string; cls: string } {
  switch (type) {
    case NotificationType.TICKET_ASSIGNED:
    case NotificationType.TASK_ASSIGNED:
      return { icon: 'fas fa-user-check', cls: styles.typeAssigned };
    case NotificationType.TICKET_SUPPORT_ASSIGNED:
      return { icon: 'fas fa-hands-helping', cls: styles.typeAssigned };
    case NotificationType.TASK_COLLABORATOR_ASSIGNED:
      return { icon: 'fas fa-user-plus', cls: styles.typeAssigned };
    case NotificationType.TASK_REASSIGNED:
      return { icon: 'fas fa-exchange-alt', cls: styles.typeAssigned };
    case NotificationType.NEW_MESSAGE:
      return { icon: 'fas fa-comment-dots', cls: styles.typeMessage };
    case NotificationType.STATUS_CHANGED:
      return { icon: 'fas fa-exchange-alt', cls: styles.typeStatus };
    case NotificationType.APPROVAL_NEEDED:
      return { icon: 'fas fa-stamp', cls: styles.typeApproval };
    case NotificationType.SLA_WARNING:
    case NotificationType.SLA_BREACH:
      return { icon: 'fas fa-exclamation-circle', cls: styles.typeSla };
    case NotificationType.TICKET_CREATED_FOR_DEPT:
    case NotificationType.TASK_ASSIGNED_TO_DEPT:
      return { icon: 'fas fa-building', cls: styles.typeDefault };
    default:
      return { icon: 'fas fa-bell', cls: styles.typeDefault };
  }
}

// ── Component ─────────────────────────────────────────────────────────────────

export const NotificationCenter: React.FC = () => {
  const dispatch  = useAppDispatch();
  const navigate  = useNavigate();
  const wrapperRef = useRef<HTMLDivElement>(null);

  const { items, unreadCount, loading, loadingMore, hasMore, page } =
    useAppSelector((s) => s.notifications);

  const [open,      setOpen]      = useState(false);
  const [unreadOnly, setUnreadOnly] = useState(false);

  // ── Auto-refresh list when panel is open and new notification arrives ────
  // This replaces any placeholder-ID item added by pushNotification with the
  // real server record, preventing markRead failures on a temp UUID.
  useSignalREvent(HubEvent.ReceiveNotification, (_notif) => {
    if (open) {
      dispatch(fetchNotifications(unreadOnly));
    }
  });

  // ── Toggle open / close ──────────────────────────────────────────────────
  const toggle = useCallback(() => {
    // Fetch when opening. Read `open` BEFORE calling setOpen so the check
    // reflects the current state (not the pending next state).
    if (!open) {
      dispatch(fetchNotifications(unreadOnly));
    }
    setOpen((prev) => !prev);
  }, [open, dispatch, unreadOnly]);

  // ── Refetch when tab changes ─────────────────────────────────────────────
  const handleTabChange = (unreadOnlyNext: boolean) => {
    setUnreadOnly(unreadOnlyNext);
    dispatch(fetchNotifications(unreadOnlyNext));
  };

  // ── Close on outside click or Escape ────────────────────────────────────
  useEffect(() => {
    if (!open) return;

    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setOpen(false);
    };
    const onPointerDown = (e: PointerEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };

    document.addEventListener('keydown', onKey);
    document.addEventListener('pointerdown', onPointerDown);
    return () => {
      document.removeEventListener('keydown', onKey);
      document.removeEventListener('pointerdown', onPointerDown);
    };
  }, [open]);

  // ── Click notification ────────────────────────────────────────────────────
  const handleItemClick = useCallback(
    (notif: NotificationDto) => {
      // Mark this individual notification read
      if (!notif.isRead) {
        dispatch(markNotificationRead(notif.id));
      }
      // Mark ALL notifications for the same entity read (clears badge for chat/comments)
      if (notif.entityId) {
        dispatch(markEntityNotificationsRead({ entityId: notif.entityId, types: [notif.type] }));
      }
      setOpen(false);
      if (notif.actionUrl) {
        // For NEW_MESSAGE notifications: append #chat hash so the correct tab opens.
        // The hash may already be present (backend may include it); if not, add it.
        let url = notif.actionUrl;
        if (notif.type === NotificationType.NEW_MESSAGE && !url.includes('#')) {
          url += '#chat';
        }
        navigate(url);
      }
    },
    [dispatch, navigate]
  );

  // ── Delete ────────────────────────────────────────────────────────────────
  const handleDelete = useCallback(
    (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      dispatch(deleteNotification(id));
    },
    [dispatch]
  );

  // ── Mark all read ─────────────────────────────────────────────────────────
  const handleMarkAll = useCallback(() => {
    dispatch(markAllNotificationsRead());
  }, [dispatch]);

  // ── Load more ─────────────────────────────────────────────────────────────
  const handleLoadMore = useCallback(() => {
    dispatch(fetchMoreNotifications({ unreadOnly, page: page + 1 }));
  }, [dispatch, unreadOnly, page]);

  // ── Render ────────────────────────────────────────────────────────────────
  return (
    <div ref={wrapperRef} className={styles.wrapper}>
      {/* Bell button */}
      <button
        type="button"
        aria-label="Thông báo"
        aria-haspopup="true"
        aria-expanded={open}
        className={`${styles.bellButton} ${open ? styles.active : ''}`}
        onClick={toggle}
      >
        <i className="fas fa-bell" />
        {unreadCount > 0 && (
          <span className={styles.badge}>
            {unreadCount > 99 ? '99+' : unreadCount}
          </span>
        )}
      </button>

      {/* Dropdown */}
      {open && (
        <div className={styles.panel} role="dialog" aria-label="Thông báo">
          {/* Header */}
          <div className={styles.panelHeader}>
            <h2 className={styles.panelTitle}>Thông báo</h2>
            <button
              className={styles.markAllBtn}
              onClick={handleMarkAll}
              disabled={unreadCount === 0}
              title="Đánh dấu tất cả là đã đọc"
            >
              Đọc tất cả
            </button>
          </div>

          {/* Tabs */}
          <div className={styles.tabs} role="tablist">
            <button
              role="tab"
              aria-selected={!unreadOnly}
              className={`${styles.tab} ${!unreadOnly ? styles.activeTab : ''}`}
              onClick={() => handleTabChange(false)}
            >
              Tất cả
            </button>
            <button
              role="tab"
              aria-selected={unreadOnly}
              className={`${styles.tab} ${unreadOnly ? styles.activeTab : ''}`}
              onClick={() => handleTabChange(true)}
            >
              Chưa đọc {unreadCount > 0 && `(${unreadCount})`}
            </button>
          </div>

          {/* List */}
          <div className={styles.list} role="list">
            {loading && items.length === 0 ? (
              <div className={styles.empty}>
                <i className="fas fa-spinner fa-spin" />
                <p>Đang tải...</p>
              </div>
            ) : items.length === 0 ? (
              <div className={styles.empty}>
                <i className="fas fa-bell-slash" />
                <p>Không có thông báo nào</p>
              </div>
            ) : (
              items.map((notif) => {
                const { icon, cls } = getIconClass(notif.type);
                return (
                  <div
                    key={notif.id}
                    role="listitem"
                    className={`${styles.item} ${!notif.isRead ? styles.unread : ''}`}
                    onClick={() => handleItemClick(notif)}
                  >
                    <div className={`${styles.iconWrap} ${cls}`}>
                      <i className={icon} />
                    </div>
                    <div className={styles.body}>
                      <p className={styles.itemTitle}>{notif.title}</p>
                      <p className={styles.itemMessage}>{notif.message}</p>
                      <div className={styles.meta}>
                        <span className={styles.time}>
                          {relativeTime(notif.createdAt)}
                        </span>
                      </div>
                    </div>
                    {!notif.isRead && <span className={styles.unreadDot} />}
                    <button
                      type="button"
                      aria-label="Xóa thông báo"
                      className={styles.deleteBtn}
                      onClick={(e) => handleDelete(e, notif.id)}
                    >
                      <i className="fas fa-times" />
                    </button>
                  </div>
                );
              })
            )}
          </div>

          {/* Load more */}
          {hasMore && items.length > 0 && (
            <div className={styles.loadMore}>
              <button
                className={styles.loadMoreBtn}
                disabled={loadingMore}
                onClick={handleLoadMore}
              >
                {loadingMore ? 'Đang tải...' : 'Tải thêm'}
              </button>
            </div>
          )}

          {/* View all link */}
          <div className={styles.viewAllFooter}>
            <button
              className={styles.viewAllBtn}
              onClick={() => {
                setOpen(false);
                navigate('/notifications');
              }}
            >
              Xem tất cả thông báo
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default NotificationCenter;
