import { UUID, Timestamps } from './common';

export interface User extends Timestamps {
  id: UUID;
  username: string;
  email: string;
  firstName: string;
  lastName: string;
  fullName: string;
  role: UserRole;
  departmentId: UUID;
  departmentName: string;
  skills: string[];
  avatar?: string;
  isActive: boolean;
  requirePasswordChange?: boolean;
  /** Employee ID used to login (e.g. UB0316) */
  employeeId?: string;
  /** Staff ID (mã nhân viên) — used for lookup input */
  staffId?: string;
  /** Phone number */
  phone?: string;
  /** Service package: 'Basic' | 'Premium' | 'Staff' */
  package?: string;
  /** Optional default landing URL set by admin for this account. Takes priority over role-based home. */
  defaultMenuUrl?: string;
  /** The active company ID embedded in the current JWT. */
  companyId?: string;
}

export enum UserRole {
  Admin = 'admin',
  Manager = 'manager',
  Staff = 'staff',
}

export interface UserProfile extends User {
  phoneNumber?: string;
  workload: {
    activeTickets: number;
    activeTasks: number;
    completedThisMonth: number;
  };
  performance: {
    rating: number;
    completionRate: number;
    averageResponseTime: number; // minutes
  };
}
