/**
 * MessageCenter
 *
 * Header-bar messages icon that mirrors NotificationCenter UX:
 *  - Unread badge count from messagesInboxSlice.unreadMessageCount
 *  - On open: fetches conversations + clears unread badge
 *  - Conversation list with load-more pagination
 *  - Each item: click body → opens slide-out ChatPanel
 *              click "↗" button → entity detail page (/tickets/:id etc.)
 *  - "Xem tất cả" footer → /messages
 *  - Closes on outside click or Escape
 *  - Real-time updates via SignalR (NEW_MESSAGE updates conversation preview)
 */
import React, {
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import { useNavigate } from 'react-router-dom';
import { useAppDispatch, useAppSelector } from '../../../store/hooks';
import {
  fetchConversations,
  fetchMoreConversations,
  clearUnreadMessages,
  markConversationReadLocal,
} from '../../../store/slices/messagesInboxSlice';
import { conversationEndpoint } from '../../../services/message/conversationEndpoint';
import { useSignalREvent } from '../../../services/signalr/hook';
import { HubEvent } from '../../../services/signalr/types';
import type { ConversationSummary } from '../../../services/message/conversationTypes';
import { Slideout } from '../../common/Slideout/Slideout';
import { ChatPanel } from '../../../pages/MessagesPage/components/ChatPanel/ChatPanel';
import styles from './MessageCenter.module.css';

// ── Helpers ────────────────────────────────────────────────────────────────────

function relativeTime(iso: string): string {
  const diff  = Date.now() - new Date(iso).getTime();
  const mins  = Math.floor(diff / 60_000);
  const hours = Math.floor(diff / 3_600_000);
  const days  = Math.floor(diff / 86_400_000);
  if (mins < 1)   return 'Vừa xong';
  if (mins < 60)  return `${mins} phút trước`;
  if (hours < 24) return `${hours} giờ trước`;
  if (days < 7)   return `${days} ngày trước`;
  return new Date(iso).toLocaleDateString('vi-VN');
}

function getEntityIcon(entityType: 'ticket' | 'task' | 'incident'): string {
  switch (entityType) {
    case 'ticket':   return 'fas fa-ticket-alt';
    case 'task':     return 'fas fa-tasks';
    case 'incident': return 'fas fa-exclamation-triangle';
    default:         return 'fas fa-comment-dots';
  }
}

/** Route to the entity detail page (not the messages page). */
function getDetailRoute(conv: ConversationSummary): string {
  switch (conv.entityType) {
    case 'ticket':   return `/tickets/${conv.entityId}`;
    case 'task':     return `/tasks/${conv.entityId}`;
    case 'incident': return `/medical-incidents/${conv.entityId}`;
    default:         return `/tickets/${conv.entityId}`;
  }
}


// ── Component ──────────────────────────────────────────────────────────────────

export const MessageCenter: React.FC = () => {
  const dispatch   = useAppDispatch();
  const navigate   = useNavigate();
  const wrapperRef = useRef<HTMLDivElement>(null);

  const { conversations, loading, loadingMore, hasMore, page, unreadMessageCount } =
    useAppSelector((s) => s.messagesInbox);

  const [open, setOpen] = useState(false);
  const [selectedConv, setSelectedConv] = useState<ConversationSummary | null>(null);

  // ── When panel opens: only fetch, do NOT clear badge yet ───────────────
  const openPanel = useCallback(() => {
    dispatch(fetchConversations());
    setOpen(true);
  }, [dispatch]);

  const toggle = useCallback(() => {
    if (open) {
      setOpen(false);
    } else {
      openPanel();
    }
  }, [open, openPanel]);

  // ── Real-time: refresh list when a new message arrives while open ────────
  useSignalREvent(HubEvent.NewMessage, () => {
    if (open) {
      dispatch(fetchConversations());
    }
  });

  // ── Close on outside click or Escape ────────────────────────────────────
  useEffect(() => {
    if (!open) return;

    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setOpen(false);
    };
    const onPointerDown = (e: PointerEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };

    document.addEventListener('keydown', onKey);
    document.addEventListener('pointerdown', onPointerDown);
    return () => {
      document.removeEventListener('keydown', onKey);
      document.removeEventListener('pointerdown', onPointerDown);
    };
  }, [open]);

  // ── Open slide-out chat for this conversation ───────────────────────────
  const handleItemClick = useCallback(
    (conv: ConversationSummary) => {
      setOpen(false);
      dispatch(markConversationReadLocal(conv.entityId));          // clear per-conv badge
      conversationEndpoint.markConversationRead(              // persist to backend
        conv.entityType, conv.entityId
      ).catch(() => {});
      setSelectedConv(conv);
    },
    [dispatch],
  );

  const handleCloseSlideout = useCallback(() => {
    setSelectedConv(null);
  }, []);

  // ── Open entity detail page ───────────────────────────────────────────────
  const handleOpenDetail = useCallback(
    (e: React.MouseEvent, conv: ConversationSummary) => {
      e.stopPropagation();
      setOpen(false);
      navigate(getDetailRoute(conv));
    },
    [navigate],
  );

  // ── Load more ─────────────────────────────────────────────────────────────
  const handleLoadMore = useCallback(() => {
    dispatch(fetchMoreConversations({ page: page + 1 }));
  }, [dispatch, page]);

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div ref={wrapperRef} className={styles.wrapper}>
      {/* Messages icon button */}
      <button
        type="button"
        aria-label="Tin nhắn"
        aria-haspopup="true"
        aria-expanded={open}
        className={`${styles.msgButton} ${open ? styles.active : ''}`}
        onClick={toggle}
      >
        <i className="fas fa-comments" />
        {unreadMessageCount > 0 && (
          <span className={styles.badge}>
            {unreadMessageCount > 99 ? '99+' : unreadMessageCount}
          </span>
        )}
      </button>

      {/* Dropdown panel */}
      {open && (
        <div className={styles.panel} role="dialog" aria-label="Tin nhắn">
          {/* Header */}
          <div className={styles.panelHeader}>
            <h2 className={styles.panelTitle}>Tin nhắn</h2>
          </div>

          {/* Conversation list */}
          <div className={styles.list} role="list">
            {loading && conversations.length === 0 ? (
              <div className={styles.empty}>
                <i className="fas fa-spinner fa-spin" />
                <p>Đang tải...</p>
              </div>
            ) : conversations.length === 0 ? (
              <div className={styles.empty}>
                <i className="fas fa-comment-slash" />
                <p>Không có tin nhắn nào</p>
              </div>
            ) : (
              conversations.map((conv) => (
                <div
                  key={`${conv.entityType}-${conv.entityId}`}
                  role="listitem"
                  className={`${styles.item} ${conv.unreadCount > 0 ? styles.itemUnread : ''}`}
                  onClick={() => handleItemClick(conv)}
                >
                  {/* Entity type icon */}
                  <div className={`${styles.iconWrap} ${styles[conv.entityType]}`}>
                    <i className={getEntityIcon(conv.entityType)} />
                  </div>

                  {/* Body */}
                  <div className={styles.body}>
                    <div className={styles.entityMeta}>
                      <span className={styles.idCode}>{conv.entityIdCode}</span>
                      <span className={styles.entityTitle}>{conv.entityTitle}</span>
                      {conv.unreadCount > 0 && (
                        <span className={styles.unreadBadge}>
                          {conv.unreadCount > 99 ? '99+' : conv.unreadCount}
                        </span>
                      )}
                    </div>
                    {conv.lastMessage ? (
                      <p className={styles.lastMsg}>
                        {conv.lastMessage.userName
                          ? <><strong>{conv.lastMessage.userName}:</strong> {conv.lastMessage.content}</>
                          : conv.lastMessage.content}
                      </p>
                    ) : (
                      <p className={styles.lastMsg}>Chưa có tin nhắn</p>
                    )}
                    <div className={styles.meta}>
                      {conv.lastMessage && (
                        <span className={styles.time}>
                          {relativeTime(conv.lastMessage.createdAt)}
                        </span>
                      )}
                      <span className={styles.msgCount}>
                        <i className="fas fa-comment-dots" /> {conv.totalMessageCount}
                      </span>
                    </div>
                  </div>

                  {/* Open detail page button */}
                  <button
                    type="button"
                    aria-label="Mở trang chi tiết"
                    className={styles.detailBtn}
                    title={conv.entityType === 'ticket' ? 'Mở phiếu yêu cầu' : conv.entityType === 'incident' ? 'Mở sự cố' : 'Mở công việc'}
                    onClick={(e) => handleOpenDetail(e, conv)}
                  >
                    <i className="fas fa-external-link-alt" />
                  </button>
                </div>
              ))
            )}
          </div>

          {/* Load more */}
          {hasMore && conversations.length > 0 && (
            <div className={styles.loadMore}>
              <button
                className={styles.loadMoreBtn}
                disabled={loadingMore}
                onClick={handleLoadMore}
              >
                {loadingMore ? 'Đang tải...' : 'Tải thêm'}
              </button>
            </div>
          )}

          {/* View all footer */}
          <div className={styles.viewAllFooter}>
            <button
              className={styles.viewAllBtn}
              onClick={() => {
                setOpen(false);
                dispatch(clearUnreadMessages());
                navigate('/messages');
              }}
            >
              Xem tất cả tin nhắn
            </button>
          </div>
        </div>
      )}
      {/* Chat slide-out */}
      <Slideout
        isOpen={!!selectedConv}
        onClose={handleCloseSlideout}
        title={
          selectedConv ? (
            <span style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <i className={getEntityIcon(selectedConv.entityType)} style={{ opacity: 0.7 }} />
              {selectedConv.entityTitle || selectedConv.entityIdCode}
            </span>
          ) : ''
        }
        width="520px"
      >
        {selectedConv && <ChatPanel conversation={selectedConv} />}
      </Slideout>
    </div>
  );
};

export default MessageCenter;
