/**
 * ChatPanel — wraps the existing shared ChatTab inside the Messages Inbox.
 *
 * Reuses `useMessages` hook (already joins/leaves SignalR room internally)
 * so no duplicated room management is needed here.
 */
import React, { useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import type { ConversationSummary } from '../../../../services/message/conversationTypes';
import { ChatTab } from '../../../../components/shared';
import { useMessages } from '../../../../hooks/useMessages';
import { useAppSelector } from '../../../../store/hooks';
import styles from './ChatPanel.module.css';

function getEntityIcon(entityType: 'ticket' | 'task' | 'incident'): string {
  switch (entityType) {
    case 'ticket':   return 'fas fa-ticket-alt';
    case 'task':     return 'fas fa-tasks';
    case 'incident': return 'fas fa-exclamation-triangle';
    default:         return 'fas fa-comment-dots';
  }
}

function getDetailRoute(conv: ConversationSummary): string {
  switch (conv.entityType) {
    case 'ticket':   return `/tickets/${conv.entityId}`;
    case 'task':     return `/tasks/${conv.entityId}`;
    case 'incident': return `/medical-incidents/${conv.entityId}`;
    default:         return `/tickets/${conv.entityId}`;
  }
}

interface ChatPanelProps {
  conversation: ConversationSummary;
}

export const ChatPanel: React.FC<ChatPanelProps> = ({ conversation }) => {
  const currentUser = useAppSelector((s) => s.auth.user);
  const navigate    = useNavigate();

  // mark-read is handled centrally inside useMessages (mount + visibility + new messages)

  const goToDetail = useCallback(() => {
    navigate(getDetailRoute(conversation));
  }, [navigate, conversation]);

  const {
    chatMessages,
    sendMessage,
    hasMoreChat,
    loading,
    loadMoreChat,
  } = useMessages(
    conversation.entityType as 'ticket' | 'task' | 'incident',
    conversation.entityId,
  );

  return (
    <div className={styles.panel}>
      {/* Panel header */}
      <div className={styles.header}>
        <div className={styles.headerIcon}>
          <i className={getEntityIcon(conversation.entityType)} />
        </div>
        <div className={styles.headerInfo}>
          <span className={styles.headerCode}>{conversation.entityIdCode}</span>
          <span className={styles.headerTitle}>{conversation.entityTitle}</span>
        </div>
        <span className={styles.headerStatus}>{conversation.entityStatus}</span>
        <button
          className={styles.detailBtn}
          onClick={goToDetail}
          title="Xem chi tiết"
        >
          <i className="fas fa-external-link-alt" />
          <span>Chi tiết</span>
        </button>
      </div>

      {/* Chat */}
      <div className={styles.chatWrap}>
        <ChatTab
          entityId={conversation.entityId}
          entityType={conversation.entityType as 'ticket' | 'task'}
          messages={chatMessages}
          onSendMessage={sendMessage}
          currentUserId={currentUser?.id ?? ''}
          hasMore={hasMoreChat}
          loading={loading}
          onLoadMore={loadMoreChat}
        />
      </div>
    </div>
  );
};
