/**
 * User service facade.
 * Components and Redux slices import from here ONLY.
 */

import { userEndpoint } from './endpoint';
import type { CreateUserRequest, UpdateUserRequest, GetUsersRequest } from './requestModel';

export const userService = {
  // ── Read ────────────────────────────────────────────────────────────────────

  getUsers: (params?: GetUsersRequest) => userEndpoint.getUsers(params),

  getUserById: (id: string) => userEndpoint.getUserById(id),

  getCurrentUser: () => userEndpoint.getCurrentUser(),

  getUsersByDepartment: (departmentId: string) =>
    userEndpoint.getUsersByDepartment(departmentId),

  getCandidates: (departmentId?: string, search?: string, excludeIds?: string[]) =>
    userEndpoint.getCandidates(departmentId, search, excludeIds),

  // ── Write (admin only) ──────────────────────────────────────────────────────

  createUser: (data: CreateUserRequest) => userEndpoint.createUser(data),

  updateUser: (id: string, data: UpdateUserRequest) => userEndpoint.updateUser(id, data),

  deactivateUser: (id: string) => userEndpoint.deactivateUser(id),

  // ── Stats ──────────────────────────────────────────────────────────────
  getStats: () => userEndpoint.getStats(),
};

export type { CreateUserRequest, UpdateUserRequest, GetUsersRequest };
export type { User } from '../../models/User';
