import React, { useEffect, useState } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import { navigateToUrl } from 'single-spa';
import { useAppDispatch, useAppSelector } from '../../../store/hooks';
import { logout } from '../../../store/slices/authSlice';
import { addToast } from '../../../store/slices/uiSlice';
import { pushNotification, fetchUnreadCount, clearNotifications } from '../../../store/slices/notificationSlice';
import { clearMessagesInbox, updateConversationFromMessage, fetchUnreadMessageCount, markConversationReadLocal } from '../../../store/slices/messagesInboxSlice';
import { subscriptionService } from '../../../services/notifications';
import { conversationEndpoint } from '../../../services/message/conversationEndpoint';
import { Sidebar } from '../Sidebar';
import { Topbar } from '../Topbar';
import { ErrorBoundary } from '../ErrorBoundary';
import { NotificationCenter } from '../../notifications/NotificationCenter';
import { MessageCenter } from '../../notifications/MessageCenter';
import { AppSwitcher, AppDef, APPS } from '../AppSwitcher';
import {
  getActiveApp,
  buildTaskManagementSections,
  buildMedicalIncidentSections,
} from '../../../utils/navUtils';
import { useSignalREvent } from '../../../services/signalr/hook';
import { HubEvent } from '../../../services/signalr/types';
import { signalRService } from '../../../services/signalr';
import { useBrowserNotification } from '../../../hooks/useBrowserNotification';
import { appSettings } from '../../../config/appSettings';
import { initPushNotifications, deregisterPushNotifications } from '@linm-soft/common-components';
import { UserRole } from '../../../models/User';
import { SwitchCompanyModal } from '../SwitchCompanyModal';
import { companyBrandingService } from '../../../services/companyBranding';
import styles from './AppLayout.module.css';

// ─────────────────────────────────────────────────────────────────────────────
// Nav section definitions and builders are in ../../../utils/navUtils.ts
// ─────────────────────────────────────────────────────────────────────────────

export const AppLayout: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();
  const currentUser = useAppSelector((state) => state.auth.user);
  const logoutLoading = useAppSelector((state) => state.auth.logoutLoading);
  // Web.Home does not own approvals/SLA features — those live in @linm/task.
  const unreadMessageCount = useAppSelector((state) => state.messagesInbox.unreadMessageCount);
  const silentMode = useAppSelector((state) => state.ui.silentMode);

  // Browser notification permission
  const { requestPermission, showNotification } = useBrowserNotification();

  // Request browser Push permission once after login + initial unread count
  useEffect(() => {
    if (currentUser?.id) {
      console.log(
        '[🔔 AppLayout] Init — SignalR enabled:', appSettings.enableSignalR,
        '| connected:', signalRService.isConnected,
      );
      requestPermission().then((granted) => {
        console.log(
          '[🔔 AppLayout] Browser notification permission:',
          (typeof Notification !== 'undefined' ? Notification.permission : 'N/A'),
          '| granted:', granted,
        );
        // Init Web Push (FCM or VAPID) only when permission is granted
        if (granted && appSettings.pushProvider !== 'none') {
          initPushNotifications().catch((err) =>
            console.warn('[Push] init failed:', err)
          );
        }
      });
      // Fetch unread notification count on startup
      dispatch(fetchUnreadCount());
      dispatch(fetchUnreadMessageCount());
    }
  }, [currentUser?.id, requestPermission, dispatch]);

  // Resync badge after SignalR reconnects — catches any notifications pushed
  // during the disconnected window (no polling needed; event-driven otherwise)
  useEffect(() => {
    if (!currentUser?.id) return;
    const unsub = signalRService.onReconnected(() => {
      dispatch(fetchUnreadCount());
      dispatch(fetchUnreadMessageCount());
    });
    return unsub;
  }, [currentUser?.id, dispatch]);

  // Listen for real-time SignalR notifications
  useSignalREvent(HubEvent.ReceiveNotification, (notif) => {
    console.log('[🔔 ReceiveNotification] Received →', {
      id:       notif.id,
      type:     notif.type,
      priority: notif.priority,
      title:    notif.title,
      message:  notif.message,
      isRead:   notif.isRead,
    });

    if (notif.type === 'NEW_MESSAGE') {
      // ── Chat messages → Messages Inbox (not the notification bell) ──────────

      // Check if the user is currently viewing this exact conversation:
      //   /messages/:type/:id  OR  /tickets/:id  /tasks/:id  /medical-incidents/:id
      const p = location.pathname;
      const isViewingEntity = !!(notif.entityId && notif.entityType && (
        p === `/messages/${notif.entityType}/${notif.entityId}` ||
        p.startsWith(`/tickets/${notif.entityId}`) ||
        p.startsWith(`/tasks/${notif.entityId}`) ||
        p.startsWith(`/medical-incidents/${notif.entityId}`)
      ));

      // Only skip increment if user is truly active on the page (visible + focused)
      const isPageActive = isViewingEntity
        && document.visibilityState === 'visible'
        && document.hasFocus();

      if (isPageActive) {
        // User is actively looking at this chat — mark read immediately, no badge
        dispatch(markConversationReadLocal(notif.entityId!));
        conversationEndpoint.markConversationRead(
          notif.entityType as 'ticket' | 'task' | 'incident',
          notif.entityId!
        ).catch(() => {});
      }
      // (no else-incrementUnreadMessages: updateConversationFromMessage below recalculates total)

      // Auto-register the receiving user as a subscriber so they appear
      // in GET /messages/conversations on the next load
      if (notif.entityId && notif.entityType) {
        subscriptionService.registerSubscription(
          notif.entityType as 'ticket' | 'task' | 'incident',
          notif.entityId
        ).catch(() => { /* non-blocking */ });
      }

      // Update conversation preview in real-time if entity info is present
      if (notif.entityId && notif.entityType) {
        dispatch(
          updateConversationFromMessage({
            entityId:   notif.entityId,
            entityType: notif.entityType as 'ticket' | 'task' | 'incident',
            lastMessage: {
              content:   notif.message,
              userName:  '',   // sender name not in NotificationDto; refreshed on next open
              createdAt: notif.createdAt,
            },
          }),
        );
      }
    } else {
      // ── System/assignment/status notifications → bell ────────────────────────
      dispatch(pushNotification(notif));

      if (!silentMode) {
        const toastType =
          notif.priority === 'CRITICAL' ? 'error' :
          notif.priority === 'HIGH'     ? 'warning' : 'info';
        dispatch(addToast({ message: `${notif.title}: ${notif.message}`, type: toastType }));
      }
    }

    // Browser OS notification — always (both message and system types),
    // but only when push provider is 'none' (no VAPID/FCM duplicate)
    if (appSettings.pushProvider === 'none') {
      showNotification(notif.title, notif.message, {
        tag: notif.id,
        actionUrl: notif.actionUrl,
      });
    }
  });

  // Listen for department-broadcast notifications (Dept_{deptId} group)
  useSignalREvent(HubEvent.DeptNotification, (notif) => {
    console.log('[🏥 DeptNotification] Received →', {
      id:       notif.id,
      type:     notif.type,
      priority: notif.priority,
      title:    notif.title,
      message:  notif.message,
    });

    dispatch(pushNotification(notif));

    if (!silentMode) {
      const toastType =
        notif.priority === 'CRITICAL' ? 'error' :
        notif.priority === 'HIGH'     ? 'warning' : 'info';
      dispatch(addToast({ message: `${notif.title}: ${notif.message}`, type: toastType }));
    }

    showNotification(notif.title, notif.message, {
      tag: `dept-${notif.id}`,
      actionUrl: notif.actionUrl,
    });
  });

  // ── Visibility-change: refresh unread count when user returns to the app ──
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible' && currentUser?.id) {
        dispatch(fetchUnreadCount());
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [currentUser?.id, dispatch]);

  // Sidebar collapse state management
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(() => {
    if (typeof window === 'undefined') return false;
    const width = window.innerWidth;
    if (width <= 680) return false; // Never collapsed on mobile
    if (width <= 1024) return true; // Default collapsed on small desktop
    const saved = localStorage.getItem('sidebar-collapsed-preference');
    return saved === 'collapsed';
  });

  const [isMobile, setIsMobile] = useState(() => 
    typeof window !== 'undefined' && window.innerWidth <= 680
  );

  const [isSmallDesktop, setIsSmallDesktop] = useState(() => 
    typeof window !== 'undefined' && window.innerWidth > 680 && window.innerWidth <= 1024
  );

  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [isSwitchCompanyOpen, setIsSwitchCompanyOpen] = useState(false);

  const companyLogoUrl = companyBrandingService.get()?.logoUrl;

  // Detect active app from URL
  const activeApp = getActiveApp(location.pathname);
  const activeAppDef = APPS.find((a) => a.id === activeApp) ?? APPS[0];

  // Fetch approval stats and SLA stats on mount
  useEffect(() => {
    // To-do: next feature will display these stats in the sidebar badges, so we fetch them here to have them ready globally
    // dispatch(fetchApprovalStats());
    // dispatch(fetchSLAStats());
  }, [dispatch]);

  // Handle window resize and responsive behavior
  useEffect(() => {
    const handleResize = () => {
      const width = window.innerWidth;
      const newIsMobile = width <= 680;
      const newIsSmallDesktop = width > 680 && width <= 1024;
      
      setIsMobile(newIsMobile);
      setIsSmallDesktop(newIsSmallDesktop);
      
      // Auto-collapse/expand based on breakpoint
      if (!newIsMobile && width <= 1024 && !isSidebarCollapsed) {
        setIsSidebarCollapsed(true);
      } else if (width > 1024) {
        const saved = localStorage.getItem('sidebar-collapsed-preference');
        setIsSidebarCollapsed(saved === 'collapsed');
      } else if (newIsMobile) {
        setIsSidebarCollapsed(false);
      }
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [isSidebarCollapsed]);

  // Build role-filtered nav sections (approvals/SLA badges always 0 in Web.Home — owned by @linm/task)
  const approvalBadge = 0;
  const slaAlertsBadge = 0;
  const currentNavSections =
    activeApp === 'medical-incidents'
      ? buildMedicalIncidentSections(currentUser?.role)
      : buildTaskManagementSections(currentUser?.role, approvalBadge, slaAlertsBadge, currentUser?.package, unreadMessageCount);

  const handleNavigate = (path: string) => {
    navigate(path);
    // Close mobile sidebar on navigation
    if (isMobile) {
      setIsMobileSidebarOpen(false);
    }
  };

  const handleAppSwitch = (app: AppDef) => {
    navigateToUrl(app.homeRoute);
    if (isMobile) setIsMobileSidebarOpen(false);
  };

  const handleToggleMobileSidebar = () => {
    setIsMobileSidebarOpen(!isMobileSidebarOpen);
  };

  const handleToggleSidebar = () => {
    const newState = !isSidebarCollapsed;
    setIsSidebarCollapsed(newState);
    if (!isMobile) {
      localStorage.setItem('sidebar-collapsed-preference', 
        newState ? 'collapsed' : 'expanded');
    }
  };

  const handleLogout = async () => {
    // Guard: do not re-trigger if already logging out
    if (logoutLoading) return;

    try {
      // Deregister push subscription/token before clearing auth state
      if (appSettings.pushProvider !== 'none') {
        await deregisterPushNotifications().catch(() => {});
      }
      await dispatch(logout()).unwrap();
    } catch (error: unknown) {
      // Backend logout failed — state was already cleared by the thunk.
      // Log the error but always proceed to the login page.
      console.error('[AppLayout] Logout backend error (force clean-up applied):', error);
    } finally {
      // Clear notification state so the badge and list don't bleed into the
      // next session (or next user logging in on the same device).
      dispatch(clearNotifications());
      dispatch(clearMessagesInbox());
      dispatch(addToast({
        message: 'Đăng xuất thành công',
        type: 'success',
      }));
      navigate('/login');
    }
  };

  const getPageTitle = () => {
    const path = location.pathname;
    if (path === '/dashboard') return 'Bảng điều khiển';
    if (path === '/tickets') return 'Phiếu yêu cầu';
    if (path === '/tasks') return 'Công việc của tôi';
    if (path === '/task-pool') return 'Công việc chờ nhận';
    if (path === '/approvals') return 'Phê duyệt';
    if (path === '/sla-alerts') return 'Cảnh báo SLA';
    if (path === '/reports') return 'Báo cáo & Phân tích';
    if (path === '/admin/companies') return 'Quản lý Công ty';
    if (path === '/admin/package-config') return 'Cấu hình gói tính năng';
    if (path.startsWith('/messages')) return 'Tin nhắn';
    if (path === '/medical-incidents') return 'Danh Sách Sự Cố Y Khoa';
    if (path === '/medical-incidents/reports') return 'Báo Cáo Thống Kê SCYK';
    if (path === '/medical-incidents/reports/service-mismatch') return 'Báo Cáo Nhầm Dịch Vụ';
    if (path === '/medical-incidents/reports/fall') return 'Báo Cáo Sự Cố Té Ngã';
    if (path === '/medical-incidents/new') return 'Báo Cáo Sự Cố Mới';
    if (path.startsWith('/medical-incidents/')) return 'Chi Tiết Sự Cố';
    if (path === '/fall-location-warnings') return 'Cảnh Báo Vị Trí Té Ngã';
    if (path === '/fall-location-warnings/new') return 'Thêm Cảnh Báo Vị Trí Té Ngã';
    if (path.startsWith('/fall-location-warnings/')) return 'Chi Tiết Cảnh Báo Vị Trí Té Ngã';
    return activeAppDef.name;
  };

  // Helper to get user role label in Vietnamese
  const getUserRoleLabel = (role?: string) => {
    switch (role) {
      case 'admin':
        return 'Quản trị viên';
      case 'manager':
        return 'Quản lý';
      case 'staff':
        return 'Nhân viên';
      default:
        return 'Người dùng';
    }
  };

  // Helper to get user initials
  const getUserInitials = (fullName?: string) => {
    if (!fullName) return 'NN';
    const parts = fullName.split(' ');
    if (parts.length >= 2) {
      return (parts[parts.length - 2].charAt(0) + parts[parts.length - 1].charAt(0)).toUpperCase();
    }
    return fullName.charAt(0).toUpperCase();
  };

  return (
    <div className={styles.layout}>
      {/* Mobile overlay */}
      {isMobile && isMobileSidebarOpen && (
        <div 
          className={`${styles.overlay} ${isMobileSidebarOpen ? styles.show : ''}`}
          onClick={() => setIsMobileSidebarOpen(false)}
        />
      )}
      <Sidebar
        sections={currentNavSections}
        activePath={location.pathname}
        userName={currentUser?.fullName || 'Người dùng'}
        userRole={getUserRoleLabel(currentUser?.role)}
        userInitials={getUserInitials(currentUser?.fullName)}
        onNavigate={handleNavigate}
        onLogout={handleLogout}
        logoutLoading={logoutLoading}
        isCollapsed={isSidebarCollapsed}
        onToggleCollapse={handleToggleSidebar}
        isMobile={isMobile}
        isSmallDesktop={isSmallDesktop}
        isOpen={isMobileSidebarOpen}
        logoIcon={activeAppDef.icon}
        logoLabel={activeAppDef.name}
        logoImgUrl={companyLogoUrl}
      />
      <div className={`${styles.main} ${isSidebarCollapsed ? styles.sidebarCollapsed : ''}`}>
        <Topbar
          title={getPageTitle()}
          onSearch={(query) => console.log('Search:', query)}
          showMenuButton={isMobile}
          onMenuClick={handleToggleMobileSidebar}
          notificationSlot={<NotificationCenter />}
          rightSlot={
            <>
              {currentUser?.role === UserRole.Admin && (
                <button
                  className={styles.switchCompanyBtn}
                  onClick={() => setIsSwitchCompanyOpen(true)}
                  title="Chuyển đổi công ty"
                  aria-label="Chuyển đổi công ty"
                >
                  <i className="fas fa-exchange-alt" />
                  {!isMobile && <span className={styles.switchCompanyLabel}>Đổi công ty</span>}
                </button>
              )}
              <MessageCenter />
            </>
          }
          leftSlot={
            <AppSwitcher
              activeApp={activeApp}
              onSwitch={handleAppSwitch}
            />
          }
        />
        {currentUser?.role === UserRole.Admin && (
          <SwitchCompanyModal
            isOpen={isSwitchCompanyOpen}
            onClose={() => setIsSwitchCompanyOpen(false)}
          />
        )}
        <div className={styles.content}>
          <ErrorBoundary>
            <Outlet />
          </ErrorBoundary>
        </div>
      </div>
    </div>
  );
};

export default AppLayout;
