/**
 * PrivacyTab Component
 * Privacy settings and data export
 */

import React, { useState } from 'react';
import { UserSettings, PrivacySettings, ProfileVisibility, getProfileVisibilityLabel } from '../../../models/Settings';
import { settingsService } from '../../../services/settingsService';
import { useAlert } from '../../../components/common/Alert';
import styles from './PrivacyTab.module.css';

interface PrivacyTabProps {
  settings: UserSettings;
  onSave: (settings: Partial<UserSettings>) => void;
  saving: boolean;
}

export const PrivacyTab: React.FC<PrivacyTabProps> = ({ settings, onSave, saving }) => {
  const alert = useAlert();
  const [privacy, setPrivacy] = useState<PrivacySettings>(settings.privacy);
  const [exportLoading, setExportLoading] = useState(false);

  const handleChange = (field: keyof PrivacySettings, value: any) => {
    setPrivacy((prev) => ({
      ...prev,
      [field]: value,
    }));
  };

  const handleSave = () => {
    onSave({ privacy });
  };

  const handleExportData = async () => {
    try {
      setExportLoading(true);
      const blob = await settingsService.exportUserData();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `user-data-${Date.now()}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err: any) {
      alert.error(err.message || 'Không thể xuất dữ liệu');
    } finally {
      setExportLoading(false);
    }
  };

  return (
    <div className={styles.privacyTab}>
      {/* Profile Visibility */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Quyền riêng tư Hồ sơ</h3>
          <p className={styles.cardDescription}>
            Kiểm soát thông tin nào của bạn hiển thị với người khác
          </p>
        </div>

        <div className={styles.cardBody}>
          <div className={styles.formGroup}>
            <label className={styles.label}>Hiển thị hồ sơ</label>
            <select
              className={styles.select}
              value={privacy.profileVisibility}
              onChange={(e) => handleChange('profileVisibility', e.target.value as ProfileVisibility)}
            >
              {Object.values(ProfileVisibility).map((visibility) => (
                <option key={visibility} value={visibility}>
                  {getProfileVisibilityLabel(visibility)}
                </option>
              ))}
            </select>
            <span className={styles.helpText}>
              {privacy.profileVisibility === ProfileVisibility.Public && 'Mọi người có thể xem hồ sơ của bạn'}
              {privacy.profileVisibility === ProfileVisibility.Team && 'Chỉ thành viên trong nhóm có thể xem hồ sơ'}
              {privacy.profileVisibility === ProfileVisibility.Private && 'Chỉ bạn có thể xem hồ sơ của mình'}
            </span>
          </div>

          <div className={styles.formGroup}>
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={privacy.showOnlineStatus}
                onChange={(e) => handleChange('showOnlineStatus', e.target.checked)}
              />
              <div>
                <span className={styles.checkboxTitle}>Hiển thị trạng thái online</span>
                <span className={styles.checkboxDescription}>
                  Cho phép người khác biết khi bạn đang online
                </span>
              </div>
            </label>
          </div>

          <div className={styles.formGroup}>
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={privacy.showEmail}
                onChange={(e) => handleChange('showEmail', e.target.checked)}
              />
              <div>
                <span className={styles.checkboxTitle}>Hiển thị email</span>
                <span className={styles.checkboxDescription}>
                  Cho phép người khác xem địa chỉ email của bạn
                </span>
              </div>
            </label>
          </div>

          <div className={styles.formGroup}>
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={privacy.showPhone}
                onChange={(e) => handleChange('showPhone', e.target.checked)}
              />
              <div>
                <span className={styles.checkboxTitle}>Hiển thị số điện thoại</span>
                <span className={styles.checkboxDescription}>
                  Cho phép người khác xem số điện thoại của bạn
                </span>
              </div>
            </label>
          </div>
        </div>

        <div className={styles.cardFooter}>
          <button
            onClick={handleSave}
            className={styles.saveButton}
            disabled={saving}
          >
            {saving ? (
              <>
                <i className="fas fa-spinner fa-spin"></i> Đang lưu...
              </>
            ) : (
              <>
                <i className="fas fa-save"></i> Lưu thay đổi
              </>
            )}
          </button>
        </div>
      </div>

      {/* Data Privacy */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Quyền riêng tư Dữ liệu</h3>
          <p className={styles.cardDescription}>
            Quản lý cách dữ liệu của bạn được sử dụng
          </p>
        </div>

        <div className={styles.cardBody}>
          <div className={styles.formGroup}>
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={privacy.allowDataCollection}
                onChange={(e) => handleChange('allowDataCollection', e.target.checked)}
              />
              <div>
                <span className={styles.checkboxTitle}>Cho phép thu thập dữ liệu</span>
                <span className={styles.checkboxDescription}>
                  Giúp cải thiện trải nghiệm bằng cách thu thập dữ liệu sử dụng
                </span>
              </div>
            </label>
          </div>

          <div className={styles.formGroup}>
            <label className={styles.checkboxLabel}>
              <input
                type="checkbox"
                checked={privacy.allowAnalytics}
                onChange={(e) => handleChange('allowAnalytics', e.target.checked)}
              />
              <div>
                <span className={styles.checkboxTitle}>Cho phép phân tích</span>
                <span className={styles.checkboxDescription}>
                  Cho phép hệ thống phân tích hành vi sử dụng để cải thiện dịch vụ
                </span>
              </div>
            </label>
          </div>
        </div>
      </div>

      {/* Data Export (GDPR) */}
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Xuất Dữ liệu</h3>
          <p className={styles.cardDescription}>
            Tải xuống bản sao dữ liệu cá nhân của bạn (tuân thủ GDPR)
          </p>
        </div>

        <div className={styles.cardBody}>
          <div className={styles.dataExport}>
            <div className={styles.exportInfo}>
              <i className="fas fa-download"></i>
              <div>
                <div className={styles.exportTitle}>Xuất toàn bộ dữ liệu cá nhân</div>
                <div className={styles.exportDescription}>
                  Bao gồm hồ sơ, cài đặt và lịch sử hoạt động của bạn
                </div>
              </div>
            </div>
            <button
              onClick={handleExportData}
              className={styles.exportButton}
              disabled={exportLoading}
            >
              {exportLoading ? (
                <>
                  <i className="fas fa-spinner fa-spin"></i> Đang xuất...
                </>
              ) : (
                <>
                  <i className="fas fa-file-download"></i> Xuất dữ liệu
                </>
              )}
            </button>
          </div>

          <div className={styles.notice}>
            <i className="fas fa-info-circle"></i>
            <span>
              Dữ liệu sẽ được xuất dưới dạng file JSON. Quá trình này có thể mất vài phút.
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};
