/**
 * Real BFF API calls for User endpoints.
 * Uses apiClient exclusively – no mock data here.
 */

import { User } from '../../models/User';
import { apiClient } from '../api';
import { BffResponse, unwrap } from '../shared/bffEnvelope';
import { BffUserDto, BffUserPagedResult, BffUserStatsDto } from './responseModel';
import { mapBffUser } from './mapper';
import type { CreateUserRequest, UpdateUserRequest } from './requestModel';

export type UserPagedResponse = {
  items:      User[];
  totalCount: number;
  page:       number;
  pageSize:   number;
  totalPages: number;
};

export const userEndpoint = {
  // ── Read ────────────────────────────────────────────────────────────────────

  getUsers: async (params?: {
    search?: string;
    role?: string;
    departmentId?: string;
    includeInactive?: boolean;
    page?: number;
    pageSize?: number;
  }): Promise<UserPagedResponse> => {
    const qs = new URLSearchParams();
    if (params?.search)          qs.set('search', params.search);
    if (params?.role)            qs.set('role', params.role);
    if (params?.departmentId)    qs.set('departmentId', params.departmentId);
    if (params?.includeInactive) qs.set('includeInactive', 'true');
    qs.set('page',     String(params?.page     ?? 1));
    qs.set('pageSize', String(params?.pageSize ?? 20));
    const res = await apiClient.get<BffResponse<BffUserPagedResult>>(`/users?${qs}`);
    const data = unwrap(res);
    return {
      items:      data.items.map(mapBffUser),
      totalCount: data.totalCount,
      page:       data.page,
      pageSize:   data.pageSize,
      totalPages: data.totalPages,
    };
  },

  getUserById: async (id: string): Promise<User> => {
    const res = await apiClient.get<BffResponse<BffUserDto>>(`/users/${id}`);
    return mapBffUser(unwrap(res));
  },

  getCurrentUser: async (): Promise<User> => {
    const res = await apiClient.get<BffResponse<BffUserDto>>('/users/me');
    return mapBffUser(unwrap(res));
  },

  getUsersByDepartment: async (departmentId: string): Promise<User[]> => {
    const res = await apiClient.get<BffResponse<BffUserDto[]>>(
      `/users?departmentId=${encodeURIComponent(departmentId)}`
    );
    return unwrap(res).map(mapBffUser);
  },

  getCandidates: async (
    departmentId?: string,
    search?: string,
    excludeIds?: string[],
  ): Promise<User[]> => {
    const qs = new URLSearchParams();
    if (departmentId) qs.set('departmentId', departmentId);
    if (search)       qs.set('search', search);
    if (excludeIds?.length) qs.set('excludeIds', excludeIds.join(','));
    const res = await apiClient.get<BffResponse<BffUserDto[]>>(`/users/candidates?${qs}`);
    return unwrap(res).map(mapBffUser);
  },

  // ── Write (admin only) ──────────────────────────────────────────────────────

  createUser: async (data: CreateUserRequest): Promise<User> => {
    const res = await apiClient.post<BffResponse<BffUserDto>>('/users', data);
    return mapBffUser(unwrap(res));
  },

  updateUser: async (id: string, data: UpdateUserRequest): Promise<User> => {
    const res = await apiClient.put<BffResponse<BffUserDto>>(`/users/${id}`, data);
    return mapBffUser(unwrap(res));
  },

  deactivateUser: async (id: string): Promise<void> => {
    await apiClient.delete(`/users/${id}`);
  },

  // ── Stats ──────────────────────────────────────────────────────────────────

  /**
   * GET /users/stats
   * Returns aggregate counts for all users, independent of pagination.
   */
  getStats: async (): Promise<BffUserStatsDto> => {
    const res = await apiClient.get<BffResponse<BffUserStatsDto>>('/users/stats');
    return unwrap(res);
  },
};
