/**
 * NotificationsTab Component
 * Notification preferences and Do Not Disturb settings
 */

import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { UserSettings, NotificationSettings } from '../../../models/Settings';
import { initPushNotifications } from '@linm-soft/common-components';
import { useAppDispatch, useAppSelector } from '../../../store/hooks';
import { toggleSilentMode } from '../../../store/slices/uiSlice';
import styles from './NotificationsTab.module.css';

interface NotificationsTabProps {
  settings: UserSettings;
  onSave: (settings: Partial<UserSettings>) => void;
  saving: boolean;
}

export const NotificationsTab: React.FC<NotificationsTabProps> = ({ settings, onSave, saving }) => {
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const silentMode = useAppSelector((state) => state.ui.silentMode);
  const [notifications, setNotifications] = useState<NotificationSettings>(settings.notifications);
  const [pushPermission, setPushPermission] = useState<NotificationPermission>('default');
  const [pushRequesting, setPushRequesting] = useState(false);
  const [pushSubscribing, setPushSubscribing] = useState(false);
  const [pushToast, setPushToast] = useState<{ type: 'success' | 'error' | 'info'; msg: string } | null>(null);

  useEffect(() => {
    if ('Notification' in window) {
      setPushPermission(Notification.permission);
    }
  }, []);

  const handleRequestPushPermission = useCallback(async () => {
    if (!('Notification' in window)) return;
    setPushRequesting(true);
    setPushToast(null);
    try {
      const result = await Notification.requestPermission();
      setPushPermission(result);
      if (result === 'granted') {
        await initPushNotifications();
        setPushToast({ type: 'success', msg: 'Đã cấp quyền và đăng ký push notification thành công ✅' });
      } else if (result === 'denied') {
        setPushToast({ type: 'error', msg: 'Quyền bị từ chối. Xem hướng dẫn để bật lại.' });
      }
    } catch {
      setPushToast({ type: 'error', msg: 'Không thể yêu cầu quyền thông báo.' });
    } finally {
      setPushRequesting(false);
    }
  }, []);

  const handleResubscribePush = useCallback(async () => {
    if (pushPermission !== 'granted') return;
    setPushSubscribing(true);
    setPushToast(null);
    try {
      await initPushNotifications();
      setPushToast({ type: 'success', msg: 'Đăng ký lại push notification thành công ✅' });
    } catch {
      setPushToast({ type: 'error', msg: 'Đăng ký lại thất bại. Thử reload trang và đăng nhập lại.' });
    } finally {
      setPushSubscribing(false);
    }
  }, [pushPermission]);

  const handleChannelChange = (
    channel: 'email' | 'push' | 'sms',
    field: string,
    value: boolean
  ) => {
    setNotifications((prev) => ({
      ...prev,
      [channel]: {
        ...prev[channel],
        [field]: value,
      },
    }));
  };

  const handleDNDChange = (field: string, value: any) => {
    setNotifications((prev) => ({
      ...prev,
      doNotDisturb: {
        ...prev.doNotDisturb,
        [field]: value,
      },
    }));
  };

  const handleSave = () => {
    onSave({ notifications });
  };

  const notificationTypes = [
    { id: 'newAssignment', label: 'Công việc mới được phân công' },
    { id: 'statusChange', label: 'Thay đổi trạng thái công việc' },
    { id: 'slaWarning', label: 'Cảnh báo SLA sắp hết hạn' },
    { id: 'slaBreach', label: 'Vi phạm SLA' },
    { id: 'comment', label: 'Bình luận mới' },
    { id: 'approval', label: 'Yêu cầu phê duyệt' },
    { id: 'dailyDigest', label: 'Tóm tắt hàng ngày' },
    { id: 'weeklyReport', label: 'Báo cáo hàng tuần' },
  ];

  return (
    <div className={styles.notificationsTab}>
      <div className={styles.card}>
        <div className={styles.cardHeader}>
          <h3 className={styles.cardTitle}>Cài đặt Thông báo</h3>
          <p className={styles.cardDescription}>
            Quản lý cách bạn nhận thông báo từ hệ thống
          </p>
        </div>

        <div className={styles.cardBody}>
          {/* Notification Channels */}
          <div className={styles.section}>
            <h4 className={styles.sectionTitle}>Kênh thông báo</h4>
            
            <div className={styles.notificationTable}>
              <div className={styles.tableHeader}>
                <div className={styles.headerCell}>Loại thông báo</div>
                <div className={styles.headerCell}>Email</div>
                <div className={styles.headerCell}>Push</div>
                <div className={styles.headerCell}>SMS</div>
              </div>

              {notificationTypes.map((type) => (
                <div key={type.id} className={styles.tableRow}>
                  <div className={styles.typeCell}>{type.label}</div>
                  <div className={styles.checkCell}>
                    <label className={styles.checkbox}>
                      <input
                        type="checkbox"
                        checked={notifications.email[type.id as keyof typeof notifications.email] as boolean}
                        onChange={(e) =>
                          handleChannelChange('email', type.id, e.target.checked)
                        }
                      />
                      <span className={styles.checkmark}></span>
                    </label>
                  </div>
                  <div className={styles.checkCell}>
                    <label className={styles.checkbox}>
                      <input
                        type="checkbox"
                        checked={notifications.push[type.id as keyof typeof notifications.push] as boolean}
                        onChange={(e) =>
                          handleChannelChange('push', type.id, e.target.checked)
                        }
                      />
                      <span className={styles.checkmark}></span>
                    </label>
                  </div>
                  <div className={styles.checkCell}>
                    <label className={styles.checkbox}>
                      <input
                        type="checkbox"
                        checked={notifications.sms[type.id as keyof typeof notifications.sms] as boolean}
                        onChange={(e) =>
                          handleChannelChange('sms', type.id, e.target.checked)
                        }
                      />
                      <span className={styles.checkmark}></span>
                    </label>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Push Notification Permission */}
          <div className={styles.section}>
            <h4 className={styles.sectionTitle}>Push Notification (trình duyệt này)</h4>
            <div className={styles.pushPermissionSection}>
              {/* Status banner */}
              {'Notification' in window ? (
                <>
                  {pushPermission === 'granted' && (
                    <div className={`${styles.pushStatusBanner} ${styles.pushStatusGranted}`}>
                      <i className={`fas fa-check-circle ${styles.pushStatusIcon}`} />
                      <span className={styles.pushStatusText}>
                        <strong>Đã được cấp quyền.</strong> Trình duyệt này sẽ nhận push notification.
                      </span>
                    </div>
                  )}
                  {pushPermission === 'denied' && (
                    <div className={`${styles.pushStatusBanner} ${styles.pushStatusDenied}`}>
                      <i className={`fas fa-exclamation-triangle ${styles.pushStatusIcon}`} />
                      <span className={styles.pushStatusText}>
                        <strong>Quyền bị từ chối.</strong> Vui lòng mở Site Settings trong trình duyệt để cấp lại quyền.
                      </span>
                    </div>
                  )}
                  {pushPermission === 'default' && (
                    <div className={`${styles.pushStatusBanner} ${styles.pushStatusDefault}`}>
                      <i className={`fas fa-bell ${styles.pushStatusIcon}`} />
                      <span className={styles.pushStatusText}>
                        Chưa cấp quyền. Nhấn <strong>"Cho phép"</strong> để nhận push notification trên thiết bị này.
                      </span>
                    </div>
                  )}
                </>
              ) : (
                <div className={`${styles.pushStatusBanner} ${styles.pushStatusUnsupported}`}>
                  <i className={`fas fa-ban ${styles.pushStatusIcon}`} />
                  <span className={styles.pushStatusText}>Trình duyệt này không hỗ trợ Push Notification.</span>
                </div>
              )}

              {/* Toast feedback */}
              {pushToast && (
                <div className={`${styles.pushStatusBanner} ${
                  pushToast.type === 'success' ? styles.pushStatusGranted
                  : pushToast.type === 'error' ? styles.pushStatusDenied
                  : styles.pushStatusDefault
                }`}>
                  <i className={`fas ${
                    pushToast.type === 'success' ? 'fa-check-circle'
                    : pushToast.type === 'error' ? 'fa-times-circle'
                    : 'fa-info-circle'
                  } ${styles.pushStatusIcon}`} />
                  <span className={styles.pushStatusText}>{pushToast.msg}</span>
                </div>
              )}

              {/* Action buttons */}
              {'Notification' in window && (
                <div className={styles.pushActions}>
                  {pushPermission !== 'granted' && pushPermission !== 'denied' && (
                    <button
                      className={`${styles.pushBtn} ${styles.pushBtnPrimary}`}
                      onClick={handleRequestPushPermission}
                      disabled={pushRequesting}
                    >
                      {pushRequesting
                        ? <><i className="fas fa-spinner fa-spin" /> Đang xử lý...</>
                        : <><i className="fas fa-bell" /> Cho phép thông báo</>}
                    </button>
                  )}
                  {pushPermission === 'granted' && (
                    <button
                      className={`${styles.pushBtn} ${styles.pushBtnSecondary}`}
                      onClick={handleResubscribePush}
                      disabled={pushSubscribing}
                    >
                      {pushSubscribing
                        ? <><i className="fas fa-spinner fa-spin" /> Đang đăng ký...</>
                        : <><i className="fas fa-redo" /> Đăng ký lại</>}
                    </button>
                  )}
                  <button
                    className={styles.pushGuideLink}
                    onClick={() => navigate('/help/notification-guide')}
                  >
                    <i className="fas fa-question-circle" /> Xem hướng dẫn chi tiết
                  </button>
                </div>
              )}
            </div>
          </div>

          {/* Silent Mode */}
          <div className={styles.section}>
            <h4 className={styles.sectionTitle}>Chế độ yên lặng</h4>
            <p className={styles.sectionDesc}>
              Khi bật, thông báo popup (toast) sẽ bị ẩn. Badge và danh sách thông báo trong ứng dụng vẫn cập nhật bình thường.
            </p>
            <div className={styles.silentModeRow}>
              <div className={styles.silentModeInfo}>
                <i className={`fas ${silentMode ? 'fa-bell-slash' : 'fa-bell'} ${silentMode ? styles.silentIcon : styles.activeIcon}`} />
                <span className={styles.silentModeLabel}>
                  {silentMode ? 'Đang bật — không hiện thông báo popup' : 'Đang tắt — thông báo popup hiển thị bình thường'}
                </span>
              </div>
              <button
                type="button"
                className={`${styles.silentToggleBtn} ${silentMode ? styles.silentActive : ''}`}
                onClick={() => dispatch(toggleSilentMode())}
              >
                {silentMode ? <><i className="fas fa-bell-slash" /> Tắt yên lặng</> : <><i className="fas fa-bell-slash" /> Bật yên lặng</>}
              </button>
            </div>
          </div>

          {/* Do Not Disturb */}
          <div className={styles.section}>
            <h4 className={styles.sectionTitle}>Không làm phiền (Do Not Disturb)</h4>
            
            <div className={styles.formGroup}>
              <label className={styles.checkboxLabel}>
                <input
                  type="checkbox"
                  checked={notifications.doNotDisturb.enabled}
                  onChange={(e) => handleDNDChange('enabled', e.target.checked)}
                />
                <span>Bật chế độ Không làm phiền</span>
              </label>
            </div>

            {notifications.doNotDisturb.enabled && (
              <>
                <div className={styles.timeRange}>
                  <div className={styles.formGroup}>
                    <label className={styles.label}>Thời gian bắt đầu</label>
                    <input
                      type="time"
                      className={styles.input}
                      value={notifications.doNotDisturb.startTime}
                      onChange={(e) => handleDNDChange('startTime', e.target.value)}
                    />
                  </div>
                  <div className={styles.formGroup}>
                    <label className={styles.label}>Thời gian kết thúc</label>
                    <input
                      type="time"
                      className={styles.input}
                      value={notifications.doNotDisturb.endTime}
                      onChange={(e) => handleDNDChange('endTime', e.target.value)}
                    />
                  </div>
                </div>

                <div className={styles.formGroup}>
                  <label className={styles.checkboxLabel}>
                    <input
                      type="checkbox"
                      checked={notifications.doNotDisturb.overrideForCritical}
                      onChange={(e) => handleDNDChange('overrideForCritical', e.target.checked)}
                    />
                    <span>Vẫn nhận thông báo khẩn cấp</span>
                  </label>
                </div>
              </>
            )}
          </div>
        </div>

        <div className={styles.cardFooter}>
          <button
            onClick={handleSave}
            className={styles.saveButton}
            disabled={saving}
          >
            {saving ? (
              <>
                <i className="fas fa-spinner fa-spin"></i> Đang lưu...
              </>
            ) : (
              <>
                <i className="fas fa-save"></i> Lưu thay đổi
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  );
};
