import React, { useState, useMemo } from 'react';
import { useAppDispatch, useAppSelector } from '../../../store/hooks';
import { login } from '../../../store/slices/authSlice';
import { addToast } from '../../../store/slices/uiSlice';
import { authEndpoint } from '../../../services/auth/endpoint';
import { UserRole } from '../../../models/User';
import { Modal } from '../../common/Modal';
import { Slideout } from '../../common/Slideout';
import { Input } from '../../common/Input';
import { Button } from '../../common/Button';
import styles from './ForceChangePasswordSlideout.module.css';

interface Props {
  isOpen: boolean;
  /**
   * When true (default): forced password change — shown as a blocking Modal
   * that cannot be closed until the password is successfully updated.
   * When false: voluntary change (e.g. from Settings) — shown as a slide-out
   * panel that the user can dismiss.
   */
  isForced?: boolean;
  /** Called when the slide-out is closed voluntarily (only when isForced=false) */
  onClose?: () => void;
}

const ChangePasswordModal: React.FC<Props> = ({ isOpen, isForced = true, onClose }) => {
  const dispatch = useAppDispatch();
  const user = useAppSelector((state) => state.auth.user);

  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // ── Password rules based on user role ──────────────────────────────────────
  const isAdmin = user?.role === UserRole.Admin;
  const isManager = user?.role === UserRole.Manager;
  const minLength = isAdmin ? 8 : isManager ? 8 : 6;
  const requireUppercase = isAdmin || isManager;
  const requireNumber = isAdmin || isManager;
  const requireSpecialChar = isAdmin;

  const passwordRules = useMemo(() => {
    const rules = [
      {
        key: 'minLength',
        label: `Tối thiểu ${minLength} ký tự`,
        check: (pwd: string) => pwd.length >= minLength,
      },
      {
        key: 'notSameAsCurrent',
        label: 'Khác mật khẩu hiện tại',
        check: (pwd: string) => pwd.length > 0 && currentPassword.length > 0 && pwd !== currentPassword,
      },
      {
        key: 'confirmMatch',
        label: 'Xác nhận mật khẩu khớp',
        check: (_pwd: string) => confirmPassword.length > 0 && newPassword === confirmPassword,
      },
    ];

    if (requireUppercase) {
      rules.push({
        key: 'uppercase',
        label: 'Chứa ít nhất 1 chữ hoa (A-Z)',
        check: (pwd: string) => /[A-Z]/.test(pwd),
      });
    }

    if (requireNumber) {
      rules.push({
        key: 'number',
        label: 'Chứa ít nhất 1 chữ số (0-9)',
        check: (pwd: string) => /\d/.test(pwd),
      });
    }

    if (requireSpecialChar) {
      rules.push({
        key: 'special',
        label: 'Chứa ít nhất 1 ký tự đặc biệt (!@#$%...)',
        check: (pwd: string) => /[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(pwd),
      });
    }

    return rules;
  }, [minLength, requireUppercase, requireNumber, requireSpecialChar, currentPassword, confirmPassword, newPassword]);

  const allRulesPassed = useMemo(
    () => newPassword.length > 0 && passwordRules.every((r) => r.check(newPassword)),
    [newPassword, passwordRules],
  );

  const getRoleLabel = () => {
    if (isAdmin) return 'Quản trị viên';
    if (isManager) return 'Quản lý';
    return 'Nhân viên';
  };

  const resetForm = () => {
    setCurrentPassword('');
    setNewPassword('');
    setConfirmPassword('');
    setError(null);
  };

  const handleClose = () => {
    if (!isForced) {
      resetForm();
      onClose?.();
    }
  };

  const handleSubmit = async (e?: React.FormEvent) => {
    e?.preventDefault();
    setError(null);

    if (!currentPassword || !newPassword || !confirmPassword) {
      setError('Vui lòng điền đầy đủ thông tin.');
      return;
    }

    if (newPassword !== confirmPassword) {
      setError('Mật khẩu mới và xác nhận mật khẩu không khớp.');
      return;
    }

    if (newPassword.length < minLength) {
      setError(`Mật khẩu mới phải có ít nhất ${minLength} ký tự.`);
      return;
    }

    if (newPassword === currentPassword) {
      setError('Mật khẩu mới phải khác mật khẩu hiện tại.');
      return;
    }

    if (requireUppercase && !/[A-Z]/.test(newPassword)) {
      setError('Mật khẩu phải chứa ít nhất 1 chữ hoa (A-Z).');
      return;
    }

    if (requireNumber && !/\d/.test(newPassword)) {
      setError('Mật khẩu phải chứa ít nhất 1 chữ số (0-9).');
      return;
    }

    if (requireSpecialChar && !/[!@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/.test(newPassword)) {
      setError('Mật khẩu phải chứa ít nhất 1 ký tự đặc biệt.');
      return;
    }

    setLoading(true);
    try {
      await authEndpoint.changePassword({ currentPassword, newPassword });

      // Re-login with new password to get a fresh token (requirePasswordChange = false)
      const loginId = user?.employeeId || user?.username || '';
      if (loginId) {
        await dispatch(login({ username: loginId, password: newPassword })).unwrap();
      }

      if (isForced) {
        dispatch(addToast({
          message: 'Đổi mật khẩu thành công! Chào mừng bạn.',
          type: 'success',
        }));
      } else {
        dispatch(addToast({
          message: 'Đổi mật khẩu thành công!',
          type: 'success',
        }));
        resetForm();
        onClose?.();
      }
    } catch (err: any) {
      const msg =
        err?.response?.data?.message ||
        err?.message ||
        'Đổi mật khẩu thất bại. Vui lòng kiểm tra lại mật khẩu hiện tại.';
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  /** Fields shared between both forced-modal and slide-out layouts */
  const formFields = (
    <>
      {error && (
        <div className={styles.errorMessage}>
          <i className="fas fa-exclamation-circle"></i>
          <span>{error}</span>
        </div>
      )}

      <div className={styles.inputGroup}>
        <label htmlFor="cp-currentPassword">Mật khẩu hiện tại</label>
        <Input
          id="cp-currentPassword"
          type="password"
          value={currentPassword}
          onChange={(e) => setCurrentPassword(e.target.value)}
          placeholder="Nhập mật khẩu hiện tại"
          autoComplete="current-password"
          disabled={loading}
          required
        />
      </div>

      <div className={styles.inputGroup}>
        <label htmlFor="cp-newPassword">Mật khẩu mới</label>
        <Input
          id="cp-newPassword"
          type="password"
          value={newPassword}
          onChange={(e) => setNewPassword(e.target.value)}
          placeholder={`Nhập mật khẩu mới (tối thiểu ${minLength} ký tự)`}
          autoComplete="new-password"
          disabled={loading}
          required
        />
      </div>

      <div className={styles.inputGroup}>
        <label htmlFor="cp-confirmPassword">Xác nhận mật khẩu mới</label>
        <Input
          id="cp-confirmPassword"
          type="password"
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
          placeholder="Nhập lại mật khẩu mới"
          autoComplete="new-password"
          disabled={loading}
          required
        />
      </div>

      {/* Password rules with real-time validation */}
      <div className={styles.rulesBox}>
        <div className={styles.rulesHeader}>
          <i className="fas fa-shield-alt" />
          <span>Yêu cầu mật khẩu</span>
          {(isAdmin || isManager) && (
            <span className={styles.roleTag}>{getRoleLabel()}</span>
          )}
        </div>
        <ul className={styles.rulesList}>
          {passwordRules.map((rule) => {
            const passed = newPassword.length > 0 && rule.check(newPassword);
            return (
              <li key={rule.key} className={passed ? styles.rulePassed : styles.rulePending}>
                <i className={passed ? 'fas fa-check-circle' : 'far fa-circle'} />
                {rule.label}
              </li>
            );
          })}
        </ul>
      </div>
    </>
  );

  // ── Forced mode: blocking Modal ────────────────────────────────────────────
  if (isForced) {
    return (
      <Modal
        isOpen={isOpen}
        onClose={() => {/* cannot close – forced */}}
        title="Đổi mật khẩu bắt buộc"
        closeOnOverlayClick={false}
        size="sm"
      >
        <div className={styles.container}>
          <div className={styles.notice}>
            <i className="fas fa-shield-alt"></i>
            <p>
              Tài khoản của bạn yêu cầu đổi mật khẩu trước khi tiếp tục.
              Vui lòng đặt mật khẩu mới ngay bây giờ.
            </p>
          </div>

          <form onSubmit={handleSubmit} className={styles.form}>
            {formFields}
            <Button
              type="submit"
              fullWidth
              loading={loading}
              disabled={!currentPassword || !newPassword || !confirmPassword || !allRulesPassed}
            >
              {loading ? 'Đang đổi mật khẩu...' : 'Xác nhận đổi mật khẩu'}
            </Button>
          </form>
        </div>
      </Modal>
    );
  }

  // ── Voluntary mode: Slide-out panel ───────────────────────────────────────
  return (
    <Slideout
      isOpen={isOpen}
      onClose={handleClose}
      title="Đổi mật khẩu"
      width="420px"
      footer={{
        leftLabel: 'Huỷ',
        leftAction: handleClose,
        leftDisabled: loading,
        rightLabel: loading ? 'Đang đổi...' : 'Xác nhận',
        rightAction: () => handleSubmit(),
        rightDisabled: loading || !currentPassword || !newPassword || !confirmPassword || !allRulesPassed,
      }}
    >
      <div className={styles.slideoutBody}>
        {formFields}
      </div>
    </Slideout>
  );
};

export default ChangePasswordModal;


